SELECT setting_name
FROM security_settings
WHERE is_enabled_by_default = 1;

SELECT user_name 
FROM users 
ORDER BY user_name;

SELECT tier_name
FROM pricing_tiers
WHERE trial_period > 0;

SELECT COUNT(user_id) AS enabled_users_count
FROM user_security
WHERE security_id = 1 AND is_enabled = 1;
